A taste of what you can prove

import logos
import logos.tactics as t

# 1. Define a function symbolically
@logos.define
def double(x: int):
    return x + x

# 2. Calling with a real value evaluates normally
assert double(7) == 14

# 3. Prove a property: unfold the definition, then ring arithmetic
@logos.theorem
def double_is_2x(x: int):
    return double(x) == logos.lit(2) * x

logos.check(double_is_2x.proof(t.intro("x"), t.unfold(double), t.ring()))
print("Proved: double(x) = 2x")

# 4. Linear arithmetic
@logos.theorem
def double_exceeds_x(x: int):
    return (x &gt; logos.lit(0)) &gt;&gt; (double(x) &gt; x)

logos.check(double_exceeds_x.proof(t.intro("x", "h"), t.unfold(double), t.linarith()))
print("Proved: x &gt; 0 → double(x) &gt; x")

Proved: double(x) = 2x
Proved: x &gt; 0 → double(x) &gt; x

Basic Usage

import logos
import logos.tactics as t

@logos.define
def double(x: int):
    return x + x

# double is now a Function object
print(type(double))        # &lt;class 'logos.define.Function'&gt;
print(double.name)         # double
print(double.params)       # [Var('x', int)]

&lt;class 'logos.define.Function'&gt;
double
[Var(name='x', type=&lt;class 'int'&gt;)]

Composing Definitions
Defined functions can call each other:

@logos.define
def square(x: int):
    return x * x

@logos.define
def sum_of_squares(x: int, y: int):
    return square(x) + square(y)

@logos.theorem
def sos_symmetric(x: int, y: int):
    return sum_of_squares(x, y) == sum_of_squares(y, x)

logos.check(sos_symmetric.proof(
    t.intro("x", "y"),
    t.unfold(sum_of_squares),
    t.unfold(square),
    t.ring(),
))
print("Proved: sum_of_squares is symmetric")

Proved: sum_of_squares is symmetric

Case Expressions
Use logos.cases() for conditional definitions. Each branch is a (condition, value) pair:

@logos.define
def abs_val(x: int):
    return logos.cases(
        (x &gt;= logos.lit(0),  x),
        (x &lt; logos.lit(0),  -x),
    )

# Python mode still works
print(abs_val(-5))   # 5
print(abs_val(3))    # 3

CaseExpr(branches=[(Le(left=Lit(value=0), right=Lit(value=-5)), -5), (Gt(left=Lit(value=0), right=Lit(value=-5)), 5)])
CaseExpr(branches=[(Le(left=Lit(value=0), right=Lit(value=3)), 3), (Gt(left=Lit(value=0), right=Lit(value=3)), -3)])

unfold(*refs)
Replaces function applications with their definition bodies. Pass Function objects (from @logos.define).

@logos.define
def triple(x: int):
    return x + x + x

x = logos.var("x", int)

# After unfold, triple(x) becomes x + x + x
@logos.theorem
def triple_is_3x(x: int):
    return triple(x) == logos.lit(3) * x

logos.check(triple_is_3x.proof(t.intro("x"), t.unfold(triple), t.ring()))
print("Proved: triple(x) = 3x")

# Unfold multiple at once
@logos.define
def quad(x: int):
    return triple(x) + x

@logos.theorem
def quad_is_4x(x: int):
    return quad(x) == logos.lit(4) * x

logos.check(quad_is_4x.proof(t.intro("x"), t.unfold(quad), t.unfold(triple), t.ring()))
print("Proved: quad(x) = 4x")

Proved: triple(x) = 3x
Proved: quad(x) = 4x

Chaining Rewrites
Rewrite tactics can be chained to progressively transform a goal:

@logos.define
def square(x: int):
    return x * x

@logos.theorem
def sq_comm_example(x: int, y: int):
    return square(x) + square(y) == square(y) + square(x)

logos.check(sq_comm_example.proof(
    t.intro("x", "y"),
    t.unfold(square),   # square(x) → x*x, square(y) → y*y
    t.ring(),            # x*x + y*y = y*y + x*x (commutativity)
))
print("Proved: x² + y² = y² + x²")

Proved: x² + y² = y² + x²

Composing Propositions
Propositions are just Expr values — you can build helpers:

def positive(v):
    return v &gt; logos.lit(0)

def between(v, lo, hi):
    return (v &gt; lo) & (v &lt; hi)

x = logos.var("x", int)

prop = logos.forall(int, lambda x: positive(x) &gt;&gt; between(x * logos.lit(2), logos.lit(0), logos.lit(100)))
print("Proposition type:", type(prop).__name__)   # ForallNode

Proposition type: ForallNode

Propositions as First-Class Values
Propositions can be stored, passed around, and reused:

@logos.theorem
def commutativity_of_add(x: int, y: int):
    return x + y == y + x

@logos.theorem
def associativity_of_add(x: int, y: int, z: int):
    return (x + y) + z == x + (y + z)

logos.check(commutativity_of_add.proof(t.intro("x", "y"), t.ring()))
logos.check(associativity_of_add.proof(t.intro("x", "y", "z"), t.ring()))

print("Proved: commutativity and associativity")

Proved: commutativity and associativity

@logos.theorem — declare a theorem
@logos.theorem wraps a function to declare a Theorem object. No proof is run yet.

import logos
import logos.tactics as t

@logos.theorem
def add_zero(x: int):
    return x + logos.lit(0) == x

print(add_zero)             # Theorem[unverified]('add_zero')
print(add_zero.certified)   # False — not yet checked

Theorem[unverified]('add_zero')
False

The Proof List
The proof is a list of tactics applied left-to-right. When a tactic produces subgoals, the next items handle them.

@logos.theorem
def both_positive(x: int, y: int):
    return (x &gt; logos.lit(0)) &gt;&gt; ((y &gt; logos.lit(0)) &gt;&gt; ((x &gt; logos.lit(0)) & (y &gt; logos.lit(0))))

logos.check(both_positive.proof(
    t.intro("x", "y", "hx", "hy"),   # strip foralls and implications
    t.split(),                          # A & B → two subgoals
    [t.assumption()],                   # subgoal 1: x &gt; 0  (in context as hx)
    [t.assumption()],                   # subgoal 2: y &gt; 0  (in context as hy)
))
print("Proved")

Proved

What Happens When a Proof Fails
LogosProofError is raised with a clear message:

from logos.theorem import LogosProofError

@logos.theorem
def false_claim(x: int, y: int):
    return x + y == x - y   # false!

try:
    logos.check(false_claim.proof(t.intro("x", "y"), t.ring()))
except LogosProofError as e:
    print(f"Proof failed: {e}")

Proof failed: Theorem 'false_claim': ring: Add(left=Var(name='x', type=&lt;class 'int'&gt;), right=Var(name='y', type=&lt;class 'int'&gt;)) ≠ Sub(left=Var(name='x', type=&lt;class 'int'&gt;), right=Var(name='y', type=&lt;class 'int'&gt;)) after normalization
  LHS poly: {frozenset({('x', 1)}): 1, frozenset({('y', 1)}): 1}
  RHS poly: {frozenset({('x', 1)}): 1, frozenset({('y', 1)}): -1}

logos.prove(thm) — automatic proof search
When you pass a Theorem object to logos.prove, logos tries to prove it automatically using a cascade of decision procedures: ground computation, polynomial arithmetic, linear arithmetic, and structural decomposition.

# No tactic list needed — logos figures it out
@logos.theorem
def add_comm_auto(x: int, y: int):
    return x + y == y + x

logos.prove(add_comm_auto)
print(add_comm_auto.certified)   # True

True


This works for non-trivial goals too. Here is a chain with three quantified variables and two nested hypotheses — logos automatically introduces all variables, collects the hypotheses, and closes with linear arithmetic:

@logos.theorem
def le_trans(x: int, y: int, z: int):
    return (x &lt;= y) &gt;&gt; ((y &lt;= z) &gt;&gt; (x &lt;= z))

logos.prove(le_trans)
print("x ≤ y → y ≤ z → x ≤ z ✓")

x ≤ y → y ≤ z → x ≤ z ✓


For goals that need a conjunction proved, auto splits it and handles each branch separately:

@logos.theorem
def nonneg_increment(x: int):
    return (x &gt;= logos.lit(0)) &gt;&gt; ((x + logos.lit(1) &gt;= logos.lit(0)) & (x + logos.lit(1) &gt; x))

logos.prove(nonneg_increment)
print("x ≥ 0 → (x+1 ≥ 0) ∧ (x+1 &gt; x) ✓")

x ≥ 0 → (x+1 ≥ 0) ∧ (x+1 &gt; x) ✓


Pass hints to help with defined functions — auto will try unfolding them and then apply arithmetic:

@logos.define
def double(n: int):
    return n + n

@logos.theorem
def double_double(n: int):
    return double(double(n)) == logos.lit(4) * n

logos.prove(double_double, hints=[double])
print("double(double(n)) = 4n ✓")

double(double(n)) = 4n ✓


Control the search with depth and timeout:
logos.prove(my_thm, depth=8)          # search deeper
logos.prove(my_thm, timeout=2.0)      # give up after 2 seconds

Building on Proved Theorems
Once a theorem is certified, you can apply it in other proofs using the object directly:

@logos.theorem
def add_comm_v2(x: int, y: int):
    return x + y == y + x

logos.check(add_comm_v2.proof(t.intro("x", "y"), t.ring()))

# Use add_comm_v2 as an axiom object in another proof
@logos.theorem
def reorder_sum(x: int, y: int, z: int):
    return x + y + z == z + y + x

logos.check(reorder_sum.proof(t.intro("x", "y", "z"), t.ring()))
print("Proved")

Proved

A Parameterized Tactic
Most tactics are tactic factories — functions that return a tactic. This lets them take arguments:

def assert_context_has(name: str):
    """Tactic: fail if `name` is not in the goal's context."""
    def tactic(goal: Goal) -&gt; ProofTerm:
        if name not in goal.context:
            raise TacticFailed(f"assert_context_has: '{name}' not in context {list(goal.context)}")
        return goal.context[name]   # ← not a ProofTerm, just demonstrating the pattern
    return tactic

# Usage: assert_context_has("h") as a debugging tactic

Combining Custom Tactics with Builtins
Custom tactics plug in seamlessly with the built-in tactic library:

@logos.define
def abs_val(x: int):
    return logos.cases(
        (x &gt;= logos.lit(0), x),
        (x &lt; logos.lit(0), -x),
    )

# A reusable "unfold then arithmetic" pattern
def unfold_and_solve(*fns):
    """Unfold the given Function objects then try ring and linarith."""
    return t.then(
        *[t.unfold(fn) for fn in fns],
        t.first(t.refl(), t.ring(), t.linarith()),
    )

x = logos.var("x", int)
logos.check(logos.prove(
    logos.forall(int, int, lambda x, y: x + y == y + x),
    [t.intro("x", "y"), unfold_and_solve()],
))
print("unfold_and_solve worked")

unfold_and_solve worked

Combining Arithmetic Tactics
Real proofs often combine ring and linarith:

@logos.define
def double(x: int):
    return x + x

# double(x) &gt; x  when  x &gt; 0
@logos.theorem
def double_exceeds_input(x: int):
    return (x &gt; logos.lit(0)) &gt;&gt; (double(x) &gt; x)

logos.check(double_exceeds_input.proof(
    t.intro("x", "h"),
    t.unfold(double),   # double(x) → x + x
    t.linarith(),       # x + x &gt; x follows from x &gt; 0
))
print("Proved: double(x) &gt; x when x &gt; 0")

Proved: double(x) &gt; x when x &gt; 0

Basic Identities
Let’s build a small library of arithmetic identities, each proved formally.

x, y, z = logos.vars("x y z", int)

# Commutativity
@logos.theorem
def add_comm(x: int, y: int):
    return x + y == y + x

@logos.theorem
def mul_comm(x: int, y: int):
    return x * y == y * x

# Associativity
@logos.theorem
def add_assoc(x: int, y: int, z: int):
    return (x + y) + z == x + (y + z)

@logos.theorem
def mul_assoc(x: int, y: int, z: int):
    return (x * y) * z == x * (y * z)

# Distributivity
@logos.theorem
def distrib(x: int, y: int, z: int):
    return x * (y + z) == x * y + x * z

logos.check(add_comm.proof(t.intro("x", "y"), t.ring()))
logos.check(mul_comm.proof(t.intro("x", "y"), t.ring()))
logos.check(add_assoc.proof(t.intro("x", "y", "z"), t.ring()))
logos.check(mul_assoc.proof(t.intro("x", "y", "z"), t.ring()))
logos.check(distrib.proof(t.intro("x", "y", "z"), t.ring()))

print("Core arithmetic library: ✓")

Core arithmetic library: ✓

Parity

@logos.define
def double(n: int):
    return n + n

# double(n) = 2*n
@logos.theorem
def double_is_2n(n: int):
    return double(n) == logos.lit(2) * n

logos.check(double_is_2n.proof(t.intro("n"), t.unfold(double), t.ring()))
print("double(n) = 2n ✓")

# double is non-negative for non-negative inputs
@logos.theorem
def double_nonneg(n: int):
    return (n &gt;= logos.lit(0)) &gt;&gt; (double(n) &gt;= logos.lit(0))

logos.check(double_nonneg.proof(t.intro("n", "h"), t.unfold(double), t.linarith()))
print("n ≥ 0 → double(n) ≥ 0 ✓")

# double of a sum: double(x + y) = double(x) + double(y)
@logos.theorem
def double_additive(x: int, y: int):
    return double(x + y) == double(x) + double(y)

logos.check(double_additive.proof(t.intro("x", "y"), t.unfold(double), t.ring()))
print("double(x + y) = double(x) + double(y) ✓")

double(n) = 2n ✓
n ≥ 0 → double(n) ≥ 0 ✓
double(x + y) = double(x) + double(y) ✓

Difference of Squares
A classic identity used in factoring and cryptography:

@logos.define
def square(n: int):
    return n * n

@logos.theorem
def diff_of_squares(a: int, b: int):
    return (a + b) * (a - b) == square(a) - square(b)

logos.check(diff_of_squares.proof(t.intro("a", "b"), t.unfold(square), t.ring()))
print("(a+b)(a-b) = a² - b² ✓")

@logos.theorem
def square_of_sum(a: int, b: int):
    return square(a + b) == square(a) + logos.lit(2)*a*b + square(b)

logos.check(square_of_sum.proof(t.intro("a", "b"), t.unfold(square), t.ring()))
print("(a+b)² = a² + 2ab + b² ✓")

(a+b)(a-b) = a² - b² ✓
(a+b)² = a² + 2ab + b² ✓

Linear Inequalities
Reasoning about bounds — essential for algorithm correctness:

x, y = logos.vars("x y", int)

# Additive monotonicity
@logos.theorem
def add_mono(x: int, y: int, z: int):
    return (x &lt;= y) &gt;&gt; (x + z &lt;= y + z)

logos.check(add_mono.proof(t.intro("x", "y", "z", "h"), t.linarith()))
print("x ≤ y → x+z ≤ y+z ✓")

# Transitivity
@logos.theorem
def lt_trans(x: int, y: int, z: int):
    return (x &lt; y) &gt;&gt; ((y &lt; z) &gt;&gt; (x &lt; z))

logos.check(lt_trans.proof(t.intro("x", "y", "z", "hxy", "hyz"), t.linarith()))
print("x &lt; y ∧ y &lt; z → x &lt; z ✓")

# Sum of non-positives is non-positive
@logos.theorem
def neg_add_neg(x: int, y: int):
    return (x &lt;= logos.lit(0)) &gt;&gt; ((y &lt;= logos.lit(0)) &gt;&gt; (x + y &lt;= logos.lit(0)))

logos.check(neg_add_neg.proof(t.intro("x", "y", "hx", "hy"), t.linarith()))
print("x ≤ 0 ∧ y ≤ 0 → x + y ≤ 0 ✓")

x ≤ y → x+z ≤ y+z ✓
x &lt; y ∧ y &lt; z → x &lt; z ✓
x ≤ 0 ∧ y ≤ 0 → x + y ≤ 0 ✓

Triangle Inequality
Proving |a + b| ≤ |a| + |b| requires case analysis. Here’s a simplified version for non-negatives:

# For non-negative integers: (a + b) ≤ (a + b) — trivial base case
# Full triangle inequality needs case splits; here we show the setup:

@logos.theorem
def abs_nonneg(n: int):
    return (n &gt;= logos.lit(0)) &gt;&gt; (n &gt;= logos.lit(0))

logos.check(abs_nonneg.proof(t.intro("n", "h"), t.assumption()))
print("n ≥ 0 → n ≥ 0 (trivial, shows case intro works) ✓")

n ≥ 0 → n ≥ 0 (trivial, shows case intro works) ✓

Automatic Proof Search
logos.prove(thm) searches for a proof automatically. It handles multi-variable goals with nested hypotheses — no tactic list needed:

# Three variables, two nested implications: logos figures out the intro chain
# and closes with linear arithmetic
@logos.theorem
def sum_of_positives(x: int, y: int, z: int):
    return (x &gt; logos.lit(0)) &gt;&gt; ((y &gt; logos.lit(0)) &gt;&gt; ((z &gt; logos.lit(0)) &gt;&gt; (x + y + z &gt; logos.lit(0))))

logos.prove(sum_of_positives)
print("x&gt;0, y&gt;0, z&gt;0 → x+y+z&gt;0 ✓ (auto)")

x&gt;0, y&gt;0, z&gt;0 → x+y+z&gt;0 ✓ (auto)



# Conjunction goals are split and each branch solved independently
@logos.theorem
def both_bounds(x: int):
    return (x &gt;= logos.lit(0)) &gt;&gt; ((x + logos.lit(1) &gt;= logos.lit(0)) & (x + logos.lit(1) &gt; x))

logos.prove(both_bounds)
print("x≥0 → (x+1≥0) ∧ (x+1&gt;x) ✓ (auto)")

x≥0 → (x+1≥0) ∧ (x+1&gt;x) ✓ (auto)



# Function definitions as hints: auto unfolds them and applies ring/linarith
@logos.define
def increment(n: int):
    return n + logos.lit(1)

@logos.theorem
def increment_double(n: int):
    return increment(increment(n)) == n + logos.lit(2)

logos.prove(increment_double, hints=[increment])
print("increment(increment(n)) = n+2 ✓ (auto with function hint)")

increment(increment(n)) = n+2 ✓ (auto with function hint)

Pure Accumulator Functions
Accumulators are a common pattern — prove properties about their results:

@logos.define
def increment(n: int):
    """n + 1"""
    return n + logos.lit(1)

# increment is strictly greater than its input
@logos.theorem
def increment_gt(n: int):
    return increment(n) &gt; n

logos.check(increment_gt.proof(t.intro("n"), t.unfold(increment), t.linarith()))
print("increment(n) &gt; n ✓")

# increment is non-negative when input is non-negative
@logos.theorem
def increment_nonneg(n: int):
    return (n &gt;= logos.lit(0)) &gt;&gt; (increment(n) &gt;= logos.lit(0))

logos.check(increment_nonneg.proof(t.intro("n", "h"), t.unfold(increment), t.linarith()))
print("n ≥ 0 → increment(n) ≥ 0 ✓")

increment(n) &gt; n ✓
n ≥ 0 → increment(n) ≥ 0 ✓

Monotone Functions
A function is monotone if x ≤ y → f(x) ≤ f(y). This property is essential for binary search correctness:

@logos.define
def linear_fn(x: int):
    return logos.lit(3) * x + logos.lit(5)

@logos.theorem
def linear_fn_monotone(x: int, y: int):
    return (x &lt;= y) &gt;&gt; (linear_fn(x) &lt;= linear_fn(y))

logos.check(linear_fn_monotone.proof(
    t.intro("x", "y", "h"),
    t.unfold(linear_fn),
    t.linarith(),
))
print("3x + 5 is monotone ✓")

@logos.define
def square(x: int):
    return x * x

# Algebraic identity: (x+1)² = x² + 2x + 1
@logos.theorem
def square_succ(x: int):
    return square(x + logos.lit(1)) == square(x) + logos.lit(2) * x + logos.lit(1)

logos.check(square_succ.proof(t.intro("x"), t.unfold(square), t.ring()))
print("(x+1)² = x² + 2x + 1 ✓")

# Difference of squares: (x-y)*(x+y) = x² - y²
@logos.theorem
def square_diff(x: int, y: int):
    return (x - y) * (x + y) == square(x) - square(y)

logos.check(square_diff.proof(t.intro("x", "y"), t.unfold(square), t.ring()))
print("(x-y)(x+y) = x² - y² ✓")

3x + 5 is monotone ✓
(x+1)² = x² + 2x + 1 ✓
(x-y)(x+y) = x² - y² ✓

Function Composition Properties
Composition of linear scaling functions: prove that applying a 2× scale twice equals a 4× scale.

@logos.define
def scale_2(x: int):
    return logos.lit(2) * x

@logos.define
def scale_4(x: int):
    return logos.lit(4) * x

# scale_2 ∘ scale_2 = scale_4
@logos.theorem
def double_twice_is_quadruple(x: int):
    return scale_2(scale_2(x)) == scale_4(x)

logos.check(double_twice_is_quadruple.proof(
    t.intro("x"), t.unfold(scale_2), t.unfold(scale_2), t.unfold(scale_4), t.ring()
))
print("2*(2*x) = 4*x ✓")

# scale_2 preserves the sign
@logos.theorem
def scale_2_nonneg(x: int):
    return (x &gt;= logos.lit(0)) &gt;&gt; (scale_2(x) &gt;= logos.lit(0))

logos.check(scale_2_nonneg.proof(t.intro("x", "h"), t.unfold(scale_2), t.linarith()))
print("x ≥ 0 → 2x ≥ 0 ✓")

2*(2*x) = 4*x ✓
x ≥ 0 → 2x ≥ 0 ✓

Composing Function Properties
Prove properties of function compositions from properties of the parts:

@logos.define
def double(x: int):
    return logos.lit(2) * x

@logos.define
def triple(x: int):
    return logos.lit(3) * x

@logos.define
def sextuple(x: int):
    return logos.lit(6) * x

@logos.theorem
def double_triple_is_sextuple(x: int):
    return double(triple(x)) == sextuple(x)

logos.check(double_triple_is_sextuple.proof(
    t.intro("x"), t.unfold(double), t.unfold(triple), t.unfold(sextuple), t.ring()
))
print("2 * (3 * x) = 6 * x ✓")

# And multiplication is commutative in composition order
@logos.theorem
def triple_double_is_sextuple(x: int):
    return triple(double(x)) == sextuple(x)

logos.check(triple_double_is_sextuple.proof(
    t.intro("x"), t.unfold(triple), t.unfold(double), t.unfold(sextuple), t.ring()
))
print("3 * (2 * x) = 6 * x ✓")

2 * (3 * x) = 6 * x ✓
3 * (2 * x) = 6 * x ✓

API Contracts as Theorems
A real-world pattern: encode a function’s postcondition as a logos theorem. If the proof breaks, the contract was violated:

# A pricing function that applies a fixed flat discount
@logos.define
def apply_flat_discount(price: int):
    """price - 10  (fixed $10 discount)"""
    return price - logos.lit(10)

# Contract 1: discounted price is strictly less than original
@logos.theorem
def flat_discount_reduces_price(price: int):
    return apply_flat_discount(price) &lt; price

logos.check(flat_discount_reduces_price.proof(
    t.intro("price"), t.unfold(apply_flat_discount), t.linarith()
))
print("Discount contract: discounted &lt; original ✓")

# A shipping fee function
@logos.define
def add_shipping(price: int):
    """price + 5  (fixed $5 shipping)"""
    return price + logos.lit(5)

# Contract 2: after shipping, total is always greater than base price
@logos.theorem
def shipping_increases_price(price: int):
    return add_shipping(price) &gt; price

logos.check(shipping_increases_price.proof(
    t.intro("price"), t.unfold(add_shipping), t.linarith()
))
print("Shipping contract: total &gt; base price ✓")

# Contract 3: discount then shipping equals shipping then discount
@logos.theorem
def order_matters(price: int):
    return add_shipping(apply_flat_discount(price)) == apply_flat_discount(add_shipping(price))

logos.check(order_matters.proof(
    t.intro("price"),
    t.unfold(add_shipping), t.unfold(apply_flat_discount),
    t.ring(),
))
print("discount∘shipping == shipping∘discount (same result) ✓")

